 5→//! Validate command - Schema validation for Gallops JSON
 6→//!
 7→//! This module owns the validate command's Args struct and handler function.
 8→
 9→use std::path::PathBuf;
10→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
11→
12→/// Arguments for jjx_validate command
13→#[derive(clap::Args, Debug)]
14→pub struct jjrvl_ValidateArgs {
15→    /// Path to the Gallops JSON file
16→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
17→    pub file: PathBuf,
18→}
19→
20→/// Run the validate command - validate Gallops JSON schema
21→pub fn jjrvl_run_validate(args: jjrvl_ValidateArgs) -> i32 {
22→    let gallops = match Gallops::jjrg_load(&args.file) {
23→        Ok(g) => g,
24→        Err(e) => {
25→            eprintln!("jjx_validate: error loading Gallops: {}", e);
26→            return 1;
27→        }
28→    };
29→
30→    match gallops.jjrg_validate() {
31→        Ok(()) => {
32→            println!("Gallops validation passed");
33→            0
34→        }
35→        Err(errors) => {
36→            eprintln!("jjx_validate: validation failed with {} error(s):", errors.len());
37→            for error in errors {
38→                eprintln!("  - {}", error);
39→            }
40→            1
41→        }
42→    }
43→}
