  5→//! Muster command - List all Heats with summary information
  6→//!
  7→//! Implements the muster query operation which displays all heats
  8→//! with their status and pace completion counts.
  9→
 10→use std::path::PathBuf;
 11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 13→
 14→/// Arguments for muster command
 15→#[derive(clap::Args, Debug)]
 16→pub struct jjrmu_MusterArgs {
 17→    /// Path to the Gallops JSON file
 18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 19→    pub file: PathBuf,
 20→
 21→    /// Filter by heat status (racing, stabled)
 22→    #[arg(long)]
 23→    pub status: Option<String>,
 24→}
 25→
 26→/// Run the muster command - list Heats as TSV
 27→pub async fn jjrmu_run_muster(args: jjrmu_MusterArgs) -> i32 {
 28→    let gallops = match Gallops::jjrg_load(&args.file) {
 29→        Ok(g) => g,
 30→        Err(e) => {
 31→            eprintln!("jjx_muster: error: {}", e);
 32→            return 1;
 33→        }
 34→    };
 35→
 36→    // Collect heats in heat_order sequence (explicit user-defined priority order)
 37→    let ordered_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
 38→        .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
 39→        .collect();
 40→
 41→    // Apply status filter if specified
 42→    let heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = if let Some(ref filter_status) = args.status {
 43→        let filter_lowercase = filter_status.to_lowercase();
 44→        ordered_heats.into_iter().filter(|(_, heat)| {
 45→            let heat_status_str = match heat.status {
 46→                HeatStatus::Racing => "racing",
 47→                HeatStatus::Stabled => "stabled",
 48→                HeatStatus::Retired => "retired",
 49→            };
 50→            heat_status_str == filter_lowercase
 51→        }).collect()
 52→    } else {
 53→        ordered_heats
 54→    };
 55→
 56→    // Set up table with column definitions
 57→    let mut table = jjrp_Table::jjrp_new(vec![
 58→        jjrp_Column::new("₣Fire", jjrp_Align::Left),
 59→        jjrp_Column::new("Silks", jjrp_Align::Left),
 60→        jjrp_Column::new("Status", jjrp_Align::Left),
 61→        jjrp_Column::new("Done", jjrp_Align::Right),
 62→        jjrp_Column::new("Total", jjrp_Align::Right),
 63→    ]);
 64→
 65→    // Measure all rows to compute column widths
 66→    for (key, heat) in &heats_by_status {
 67→        // Count paces where state != Abandoned
 68→        let defined_count = heat.paces.values().filter(|pace| {
 69→            if let Some(tack) = pace.tacks.first() {
 70→                tack.state != PaceState::Abandoned
 71→            } else {
 72→                true
 73→            }
 74→        }).count();
 75→
 76→        // Count paces where state == Complete
 77→        let completed_count = heat.paces.values().filter(|pace| {
 78→            if let Some(tack) = pace.tacks.first() {
 79→                tack.state == PaceState::Complete
 80→            } else {
 81→                false
 82→            }
 83→        }).count();
 84→
 85→        let status_str = match heat.status {
 86→            HeatStatus::Racing => "racing",
 87→            HeatStatus::Stabled => "stabled",
 88→            HeatStatus::Retired => "retired",
 89→        };
 90→
 91→        table.jjrp_measure(&[
 92→            key,
 93→            &heat.silks,
 94→            status_str,
 95→            &completed_count.to_string(),
 96→            &defined_count.to_string(),
 97→        ]);
 98→    }
 99→
100→    // Print header and separator
101→    table.jjrp_print_header();
102→    table.jjrp_print_separator();
103→
104→    // Print data rows
105→    for (key, heat) in heats_by_status {
106→        // Count paces where state != Abandoned
107→        let defined_count = heat.paces.values().filter(|pace| {
108→            if let Some(tack) = pace.tacks.first() {
109→                tack.state != PaceState::Abandoned
110→            } else {
111→                true
112→            }
113→        }).count();
114→
115→        // Count paces where state == Complete
116→        let completed_count = heat.paces.values().filter(|pace| {
117→            if let Some(tack) = pace.tacks.first() {
118→                tack.state == PaceState::Complete
119→            } else {
120→                false
121→            }
122→        }).count();
123→
124→        let status_str = match heat.status {
125→            HeatStatus::Racing => "racing",
126→            HeatStatus::Stabled => "stabled",
127→            HeatStatus::Retired => "retired",
128→        };
129→
130→        table.jjrp_print_row(&[
131→            key,
132→            &heat.silks,
133→            status_str,
134→            &completed_count.to_string(),
135→            &defined_count.to_string(),
136→        ]);
137→    }
138→
139→    // Call invitatory to check/create officium marker
140→    if let Err(e) = vvc::vvcp_invitatory().await {
141→        eprintln!("jjx_muster: warning: invitatory failed: {}", e);
142→    }
143→
144→    0
145→}
