  5→//! Parade command - Display comprehensive Heat status for project review
  6→//!
  7→//! Implements both heat view (Firemark) and pace view (Coronet).
  8→
  9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat, zjjrq_files_for_commit, zjjrq_bare_filename, zjjrq_is_infra_file};
 14→use crate::jjrs_steeplechase::{jjrs_ReinArgs, jjrs_get_entries, jjrs_SteeplechaseEntry};
 15→use std::collections::BTreeMap;
