509→/// Format commit swim lanes for a heat as a String: paces × commits matrix.
510→///
511→/// Shows when work happened on each pace and how work interleaved.
512→pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
513→    let rein_args = jjrs_ReinArgs {
514→        firemark: firemark.jjrf_as_str().to_string(),
515→        limit: 10000,
516→    };
517→
518→    let entries = jjrs_get_entries(&rein_args)?;
519→
520→    if entries.is_empty() {
521→        return Ok(String::new());
522→    }
523→
524→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
525→    let total_commits = entries.len();
526→    let max_commits: usize = 35;
527→    let truncated = total_commits > max_commits;
528→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
529→        .iter()
530→        .take(max_commits)
531→        .collect::<Vec<_>>()
532→        .into_iter()
533→        .rev()
534→        .collect();
535→
536→    // Build pace rows: ordered by first chronological appearance
537→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
538→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
539→
540→    for entry in &display_entries {
541→        if let Some(ref coronet) = entry.coronet {
542→            if !pace_index.contains_key(coronet) {
543→                let idx = pace_order.len();
544→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
545→                let ch = raw.chars().last().unwrap_or('?');
546→                let silks = heat.paces.get(coronet)
547→                    .and_then(|p| p.tacks.first())
548→                    .map(|t| t.silks.clone())
549→                    .unwrap_or_else(|| "unknown".to_string());
550→                pace_index.insert(coronet.clone(), idx);
551→                pace_order.push((coronet.clone(), ch, silks));
552→            }
553→        }
554→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
555→    }
556→
557→    let total_rows = pace_order.len();
558→
559→    if total_rows == 0 {
560→        return Ok(String::new());
561→    }
562→
563→    // Build bitmap: rows × columns
564→    let num_cols = display_entries.len();
565→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
566→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
567→
568→    for (col, entry) in display_entries.iter().enumerate() {
569→        if let Some(ref coronet) = entry.coronet {
570→            if let Some(&row) = pace_index.get(coronet) {
571→                bitmap[row][col] = true;
572→                row_commit_counts[row] += 1;
573→            }
574→        }
575→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
576→    }
577→
578→    let mut output = String::new();
579→
580→    writeln!(output).unwrap();
581→    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
582→    writeln!(output).unwrap();
583→
584→    if truncated {
585→        writeln!(output, "(showing last {} of {} commits)", max_commits, total_commits).unwrap();
586→        writeln!(output).unwrap();
587→    }
588→
589→    // Vertical legend
590→    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
591→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
592→    }
593→    writeln!(output).unwrap();
594→
595→    // Column header line
596→    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
597→    writeln!(output, "{}", header).unwrap();
598→
599→    // Bitmap rows
600→    for row in 0..total_rows {
601→        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
602→        let (term_char, count) = (pace_order[row].1, row_commit_counts[row]);
603→        writeln!(output, "{}  {}  {}c", bits, term_char, count).unwrap();
604→    }
605→
606→    Ok(output)
607→}
608→
609→/// Print commit swim lanes for a heat to stdout.
610→pub(crate) fn jjrpd_print_commit_swimlanes(firemark: &Firemark, heat: &Heat) {
611→    match jjrpd_format_commit_swimlanes(firemark, heat) {
612→        Ok(output) => print!("{}", output),
613→        Err(e) => eprintln!("jjx_show: error getting steeplechase entries: {}", e),
614→    }
615→}
616→
617→/// Print files-per-commit bitmap for a single pace.
618→///
619→/// Shows which files each commit in this pace touched.
620→/// Called after tack history in pace parade.
621→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
622→    let rein_args = jjrs_ReinArgs {
623→        firemark: firemark.jjrf_as_str().to_string(),
624→        limit: 10000,
625→    };
626→
627→    let entries = match jjrs_get_entries(&rein_args) {
628→        Ok(e) => e,
629→        Err(e) => {
630→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
631→            return;
632→        }
633→    };
634→
635→    // Filter by coronet, then reverse for chronological order
636→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
637→        .iter()
638→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
639→        .collect::<Vec<_>>()
640→        .into_iter()
641→        .rev()
642→        .collect();
643→
644→    if pace_entries.is_empty() {
645→        return;
646→    }
647→
648→    // Get files for each commit
649→    let num_commits = pace_entries.len();
650→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
651→
652→    for (col, entry) in pace_entries.iter().enumerate() {
653→        let files = zjjrq_files_for_commit(&entry.commit);
654→        for path in files {
655→            if zjjrq_is_infra_file(&path) {
656→                continue;
657→            }
658→            let bare = zjjrq_bare_filename(&path);
659→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
660→            row[col] = true;
661→        }
662→    }
663→
664→    if file_touches.is_empty() {
665→        println!();
666→        println!("Pace commits: (no project file commits)");
667→        return;
668→    }
669→
670→    println!();
671→    println!("Pace commits (x = commit touched file):");
672→    println!();
673→
674→    // Legend: commit index char, SHA, subject
675→    for (i, entry) in pace_entries.iter().enumerate() {
676→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
677→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
678→    }
679→    println!();
680→
681→    // Column header line
682→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
683→    println!("{}", header);
684→
685→    // Group by identical touch pattern
686→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
687→    for (filename, pattern) in &file_touches {
688→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
689→    }
690→    for files in pattern_groups.values_mut() {
691→        files.sort();
692→    }
693→
694→    // Sort: more touches first, then lexicographic
695→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
696→    sorted.sort_by(|(a, _), (b, _)| {
697→        let ca: usize = a.iter().filter(|&&v| v).count();
698→        let cb: usize = b.iter().filter(|&&v| v).count();
699→        cb.cmp(&ca).then_with(|| a.cmp(b))
700→    });
701→
702→    for (pattern, files) in &sorted {
703→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
704→        println!("{} {}", bits, files.join(", "));
705→    }
706→}
