  5→//! jjx_retire command - Extract complete Heat data for archival trophy
  6→//!
  7→//! Handles retire operation: optionally dry-run (preview trophy) or execute
  8→//! (write trophy, remove from gallops, delete paddock, commit).
  9→
 10→use std::path::{Path, PathBuf};
 11→
 12→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RetireArgs as LibRetireArgs};
 14→use crate::jjrs_steeplechase::{jjrs_ReinArgs as ReinArgs, jjrs_get_entries as get_entries};
 15→use crate::jjrc_core::jjrc_timestamp_date;
 16→use crate::jjrn_notch::{jjrn_format_heat_message, jjrn_HeatAction};
 17→
 18→/// Arguments for jjx_retire command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrrt_RetireArgs {
 21→    /// Path to the Gallops JSON file
 22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 23→    pub file: PathBuf,
 24→
 25→    /// Target Heat identity (Firemark)
 26→    pub firemark: String,
 27→
 28→    /// Execute the retire (write trophy, remove from gallops, delete paddock, commit)
 29→    #[arg(long)]
 30→    pub execute: bool,
 31→
 32→    /// Override size limit for commit guard (bytes)
 33→    #[arg(long)]
 34→    pub size_limit: Option<u64>,
 35→}
 36→
 37→/// Run the retire command
 38→pub fn jjrrt_run_retire(args: jjrrt_RetireArgs) -> i32 {
 39→    use std::path::Path;
 40→
 41→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
 42→        Ok(fm) => fm,
 43→        Err(e) => {
 44→            eprintln!("jjx_retire: error: {}", e);
 45→            return 1;
 46→        }
 47→    };
 48→
 49→    // Load gallops
 50→    let gallops = match Gallops::jjrg_load(&args.file) {
 51→        Ok(g) => g,
 52→        Err(e) => {
 53→            eprintln!("jjx_retire: error loading Gallops: {}", e);
 54→            return 1;
 55→        }
 56→    };
 57→
 58→    // Get steeplechase entries (filtered by firemark identity)
 59→    let rein_args = ReinArgs {
 60→        firemark: args.firemark.clone(),
 61→        limit: 1000,
 62→    };
 63→    let steeplechase = match get_entries(&rein_args) {
 64→        Ok(entries) => entries,
 65→        Err(e) => {
 66→            eprintln!("jjx_retire: warning: could not get steeplechase: {}", e);
 67→            Vec::new()
 68→        }
 69→    };
 70→
 71→    // Compute base path from gallops file
 72→    let base_path = args.file.parent()
 73→        .and_then(|p| p.parent())
 74→        .and_then(|p| p.parent())
 75→        .unwrap_or(Path::new("."));
 76→
 77→    // If --execute not specified, output trophy markdown preview
 78→    if !args.execute {
 79→        // Read paddock content
 80→        let firemark_key = firemark.jjrf_display();
 81→        let heat = match gallops.heats.get(&firemark_key) {
 82→            Some(h) => h,
 83→            None => {
 84→                eprintln!("jjx_retire: error: Heat '{}' not found", firemark_key);
 85→                return 1;
 86→            }
 87→        };
 88→        let paddock_path = base_path.join(&heat.paddock_file);
 89→        let paddock_content = match std::fs::read_to_string(&paddock_path) {
 90→            Ok(c) => c,
 91→            Err(e) => {
 92→                eprintln!("jjx_retire: error reading paddock: {}", e);
 93→                return 1;
 94→            }
 95→        };
 96→
 97→        // Build and output trophy preview
 98→        let today = jjrc_timestamp_date();
 99→        match gallops.jjrg_build_trophy_preview(&args.firemark, &paddock_content, &today, &steeplechase) {
100→            Ok(markdown) => {
101→                println!("{}", markdown);
102→                return 0;
103→            }
104→            Err(e) => {
105→                eprintln!("jjx_retire: error: {}", e);
106→                return 1;
107→            }
108→        }
109→    }
110→
111→    // --execute: perform the actual retire operation
112→
113→    // Need mutable gallops for execute path
114→    let mut gallops = gallops;
115→
116→    // Acquire lock FIRST
117→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
118→        Ok(l) => l,
119→        Err(e) => {
120→            eprintln!("jjx_retire: error: {}", e);
121→            return 1;
122→        }
123→    };
124→
125→    // Execute retire
126→    let retire_args = LibRetireArgs {
127→        firemark: args.firemark.clone(),
128→        today: jjrc_timestamp_date(),
129→    };
130→
131→    let result = match gallops.jjrg_retire(retire_args, base_path, &steeplechase) {
132→        Ok(r) => r,
133→        Err(e) => {
134→            eprintln!("jjx_retire: error: {}", e);
135→            return 1;
136→        }
137→    };
138→
139→    // Save gallops
140→    if let Err(e) = gallops.jjrg_save(&args.file) {
141→        eprintln!("jjx_retire: error saving Gallops: {}", e);
142→        return 1;
143→    }
144→
145→    // Commit using vvcm_commit with explicit file list
146→    // Files: gallops.json, trophy file (created), paddock file (deleted - git add handles this)
147→    let gallops_path = args.file.to_string_lossy().to_string();
148→    let effective_size_limit = args.size_limit.unwrap_or(200000);
149→    let commit_args = vvc::vvcm_CommitArgs {
150→        files: vec![
151→            gallops_path,
152→            result.trophy_path.clone(),
153→            result.paddock_path.clone(),
154→        ],
155→        message: jjrn_format_heat_message(&firemark, jjrn_HeatAction::Retire, &result.silks),
156→        size_limit: effective_size_limit,
157→        warn_limit: effective_size_limit / 2,
158→    };
159→
160→    match vvc::machine_commit(&lock, &commit_args) {
161→        Ok(hash) => {
162→            eprintln!("jjx_retire: committed {}", &hash[..8]);
163→        }
164→        Err(e) => {
165→            eprintln!("jjx_retire: error: commit failed: {}", e);
166→            // Rollback: restore gallops and paddock from HEAD, remove trophy
167→            let gp = args.file.to_string_lossy().to_string();
168→            let _ = std::process::Command::new("git")
169→                .args(["checkout", "HEAD", "--", &gp, &result.paddock_path])
170→                .status();
171→            let _ = std::process::Command::new("git")
172→                .args(["rm", "-f", "--cached", &result.trophy_path])
173→                .status();
174→            let _ = std::fs::remove_file(&result.trophy_path);
175→            eprintln!("jjx_retire: rolled back file changes");
176→            eprintln!("jjx_retire: retry with --size-limit <bytes> to override guard");
177→            return 1;
178→        }
179→    }
180→
181→    // Output result
182→    println!("trophy: {}", result.trophy_path);
183→    println!("Heat {} retired successfully", result.firemark);
184→
185→    0
186→    // lock released here
187→}
