 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Target Heat identity (Firemark)
 25→    pub firemark: String,
 26→
 27→    /// Legacy positional args - rejected at runtime
 28→    #[arg(trailing_var_arg = true)]
 29→    pub order: Vec<String>,
 30→
 31→    // Move mode arguments
 32→
 33→    /// Coronet to relocate within order - triggers move mode
 34→    #[arg(long, short = 'm')]
 35→    pub r#move: Option<String>,
 36→
 37→    /// Move before specified Coronet
 38→    #[arg(long, conflicts_with_all = ["after", "first", "last"])]
 39→    pub before: Option<String>,
 40→
 41→    /// Move after specified Coronet
 42→    #[arg(long, conflicts_with_all = ["before", "first", "last"])]
 43→    pub after: Option<String>,
 44→
 45→    /// Move to beginning of order
 46→    #[arg(long, conflicts_with_all = ["before", "after", "last"])]
 47→    pub first: bool,
 48→
 49→    /// Move to end of order
 50→    #[arg(long, conflicts_with_all = ["before", "after", "first"])]
 51→    pub last: bool,
 52→}
 53→
 54→/// Execute rail command - reorder Paces within a Heat
 55→pub fn jjrrl_run_rail(args: jjrrl_RailArgs) -> i32 {
 56→    use crate::jjrg_gallops::jjrg_RailArgs as LibRailArgs;
 57→    use crate::jjrn_notch::{jjrn_HeatAction, jjrn_format_heat_message};
 58→
 59→    // Acquire lock FIRST - fail fast if another operation is in progress
 60→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 61→        Ok(l) => l,
 62→        Err(e) => {
 63→            eprintln!("jjx_rail: error: {}", e);
 64→            return 1;
 65→        }
 66→    };
 67→
 68→    let order: Vec<String> = if args.order.len() == 1 && args.order[0].starts_with('[') {
 69→        match serde_json::from_str(&args.order[0]) {
 70→            Ok(v) => v,
 71→            Err(_) => args.order.clone(),
 72→        }
 73→    } else {
 74→        args.order.clone()
 75→    };
 76→
 77→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 78→        Ok(g) => g,
 79→        Err(e) => {
 80→            eprintln!("jjx_rail: error loading Gallops: {}", e);
 81→            return 1;
 82→        }
 83→    };
 84→
 85→    let firemark = args.firemark.clone();
 86→    let move_coronet = args.r#move.clone();
 87→    let move_before = args.before.clone();
 88→    let move_after = args.after.clone();
 89→    let move_first = args.first;
 90→    let move_last = args.last;
 91→
 92→    // Capture old order for no-op detection
 93→    let fm = Firemark::jjrf_parse(&firemark).expect("rail given invalid firemark");
 94→    let old_order: Vec<String> = gallops.heats.get(&fm.jjrf_display())
 95→        .map(|h| h.order.clone())
 96→        .unwrap_or_default();
 97→
 98→    let rail_args = LibRailArgs {
 99→        firemark: args.firemark,
100→        order,
101→        move_coronet: args.r#move,
102→        before: args.before,
103→        after: args.after,
104→        first: args.first,
105→        last: args.last,
106→    };
107→
108→    match gallops.jjrg_rail(rail_args) {
109→        Ok(new_order) => {
110→            // No-op detection: if order unchanged, exit 0 with message
111→            if new_order == old_order {
112→                let position = if move_first { "first" }
113→                    else if move_last { "last" }
114→                    else if move_before.is_some() { "requested position" }
115→                    else if move_after.is_some() { "requested position" }
116→                    else { "requested position" };
117→                let coronet_display = move_coronet.as_deref().unwrap_or("pace");
118→                eprintln!("jjx_rail: no change — {} is already {}", coronet_display, position);
119→                for coronet in new_order {
120→                    println!("{}", coronet);
121→                }
122→                return 0;
123→            }
124→
125→            // Compute descriptive subject for commit message
126→            let subject = if let Some(ref moved) = move_coronet {
127→                // Move mode: describe where the pace was moved
128→                let target = if move_first { "to first".to_string() }
129→                    else if move_last { "to last".to_string() }
130→                    else if let Some(ref b) = move_before { format!("before {}", b) }
131→                    else if let Some(ref a) = move_after { format!("after {}", a) }
132→                    else { "???".to_string() };
133→                format!("moved {} {}", moved, target)
134→            } else {
135→                // Order mode: list the new order
136→                format!("order: {}", new_order.join(", "))
137→            };
138→
139→            let message = jjrn_format_heat_message(&fm, jjrn_HeatAction::Rail, &subject);
140→
141→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
142→                Ok(hash) => {
143→                    eprintln!("jjx_rail: committed {}", &hash[..8]);
144→                }
145→                Err(e) => {
146→                    eprintln!("jjx_rail: error: {}", e);
147→                    return 1;
148→                }
149→            }
150→
151→            for coronet in new_order {
152→                println!("{}", coronet);
153→            }
154→            0
155→        }
156→        Err(e) => {
157→            eprintln!("jjx_rail: error: {}", e);
158→            1
159→        }
160→    }
161→    // lock released here
162→}
