114→/// Run the arm command
115→///
116→/// Sets pace state to bridled with warrant.
117→/// Creates both a tally commit and a B commit.
118→pub fn jjrtl_run_arm(args: jjrtl_ArmArgs, warrant: String) -> i32 {
119→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
120→
121→    // Acquire lock FIRST - fail fast if another operation is in progress
122→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
123→        Ok(l) => l,
124→        Err(e) => {
125→            eprintln!("jjx_arm: error: {}", e);
126→            return 1;
127→        }
128→    };
129→
130→    let mut gallops = match Gallops::jjrg_load(&args.file) {
131→        Ok(g) => g,
132→        Err(e) => {
133→            eprintln!("jjx_arm: error loading Gallops: {}", e);
134→            return 1;
135→        }
136→    };
137→
138→    // Get firemark and silks for commit message before we move args
139→    let coronet_str = args.coronet.clone();
140→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
141→        Ok(c) => {
142→            let parent_fm = c.jjrf_parent_firemark();
143→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
144→                .and_then(|h| h.paces.get(&c.jjrf_display()))
145→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
146→                .unwrap_or_else(|| coronet_str.clone());
147→            (parent_fm, silks)
148→        }
149→        Err(e) => {
150→            eprintln!("jjx_arm: error: {}", e);
151→            return 1;
152→        }
153→    };
154→
155→    let tally_args = LibTallyArgs {
156→        coronet: args.coronet,
157→        state: Some(PaceState::Bridled),
158→        direction: Some(warrant.clone()),
159→        text: None,
160→        silks: None,
161→    };
162→
163→    match gallops.jjrg_tally(tally_args) {
164→        Ok(()) => {
165→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
166→
167→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
168→                Ok(hash) => {
169→                    println!("committed {}", hash);
170→                }
171→                Err(e) => {
172→                    eprintln!("jjx_arm: error: {}", e);
173→                    return 1;
174→                }
175→            }
176→
177→            // Create B commit for bridling
178→            let coronet = match Coronet::jjrf_parse(&coronet_str) {
179→                Ok(c) => c,
180→                Err(e) => {
181→                    eprintln!("jjx_arm: error parsing coronet for B commit: {}", e);
182→                    return 1;
183→                }
184→            };
185→
186→            let agent = "arm"; // Agent that bridled the pace
187→
188→            // Build B commit message
189→            use crate::jjrn_notch::jjrn_format_bridle_message;
190→            let b_subject = jjrn_format_bridle_message(&coronet, agent, &silks);
191→            let b_message = format!("{}\n\n{}", b_subject, warrant);
192→
193→            // Create empty B commit using git directly (like chalk markers)
194→            use std::process::Command;
195→            let output = Command::new("git")
196→                .args(["commit", "--allow-empty", "-m", &b_message])
197→                .output();
198→
199→            match output {
200→                Ok(result) if result.status.success() => {
201→                    // Get commit hash
202→                    let hash_output = Command::new("git")
203→                        .args(["rev-parse", "HEAD"])
204→                        .output();
205→
206→                    if let Ok(hash_result) = hash_output {
207→                        if hash_result.status.success() {
208→                            let hash = String::from_utf8_lossy(&hash_result.stdout).trim().to_string();
209→                            println!("B commit {}", &hash[..8.min(hash.len())]);
210→                        }
211→                    }
212→                }
213→                Ok(result) => {
214→                    let stderr = String::from_utf8_lossy(&result.stderr);
215→                    eprintln!("jjx_arm: error creating B commit: {}", stderr);
216→                    return 1;
217→                }
218→                Err(e) => {
219→                    eprintln!("jjx_arm: error creating B commit: {}", e);
220→                    return 1;
221→                }
222→            }
223→
224→            eprintln!();
225→            eprintln!("Recommended: /jjc-heat-mount {} to execute", fm.jjrf_as_str());
226→            0
227→        }
228→        Err(e) => {
229→            eprintln!("jjx_arm: error: {}", e);
230→            1
231→        }
232→    }
233→    // lock released here
234→}
