  5→//! Draft command - move a Pace from one Heat to another
  6→//!
  7→//! Implements the jjx_draft subcommand and related structures.
  8→
  9→use clap::Args;
 10→use std::path::PathBuf;
 11→
 12→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 13→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 14→use crate::jjri_io::jjri_paddock_path;
 15→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 16→
 17→/// Arguments for jjx_draft command
 18→#[derive(Args, Debug)]
 19→pub struct jjrdr_DraftArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Pace identity to move (Coronet)
 25→    pub coronet: String,
 26→
 27→    /// Destination Heat identity (Firemark)
 28→    #[arg(long)]
 29→    pub to: String,
 30→
 31→    /// Insert before specified Coronet in destination
 32→    #[arg(long, conflicts_with_all = ["after", "first"])]
 33→    pub before: Option<String>,
 34→
 35→    /// Insert after specified Coronet in destination
 36→    #[arg(long, conflicts_with_all = ["before", "first"])]
 37→    pub after: Option<String>,
 38→
 39→    /// Insert at beginning of destination Heat
 40→    #[arg(long, conflicts_with_all = ["before", "after"])]
 41→    pub first: bool,
 42→}
 43→
 44→/// Handler function for draft command
 45→pub fn jjrdr_run_draft(args: jjrdr_DraftArgs) -> i32 {
 46→    use crate::jjrg_gallops::jjrg_DraftArgs as LibDraftArgs;
 47→
 48→    // Acquire lock FIRST - fail fast if another operation is in progress
 49→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 50→        Ok(l) => l,
 51→        Err(e) => {
 52→            eprintln!("jjx_draft: error: {}", e);
 53→            return 1;
 54→        }
 55→    };
 56→
 57→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 58→        Ok(g) => g,
 59→        Err(e) => {
 60→            eprintln!("jjx_draft: error loading Gallops: {}", e);
 61→            return 1;
 62→        }
 63→    };
 64→
 65→    let coronet = args.coronet.clone();
 66→    let to = args.to.clone();
 67→    let draft_args = LibDraftArgs {
 68→        coronet: args.coronet,
 69→        to: args.to,
 70→        before: args.before,
 71→        after: args.after,
 72→        first: args.first,
 73→    };
 74→
 75→    match gallops.jjrg_draft(draft_args) {
 76→        Ok(result) => {
 77→            // Save gallops
 78→            if let Err(e) = gallops.jjrg_save(&args.file) {
 79→                eprintln!("jjx_draft: error saving Gallops: {}", e);
 80→                return 1;
 81→            }
 82→
 83→            // Commit using machine_commit - draft affects source and dest paddocks
 84→            // Parse both firemarks to get paddock paths
 85→            let src_coronet = crate::jjrf_favor::jjrf_Coronet::jjrf_parse(&coronet)
 86→                .expect("draft given invalid source coronet");
 87→            let src_fm = src_coronet.jjrf_parent_firemark();
 88→            let dest_fm = Firemark::jjrf_parse(&to).expect("draft given invalid destination firemark");
 89→
 90→            let gallops_path = args.file.to_string_lossy().to_string();
 91→            let src_paddock_path = jjri_paddock_path(src_fm.jjrf_as_str());
 92→            let dest_paddock_path = jjri_paddock_path(dest_fm.jjrf_as_str());
 93→
 94→            let commit_args = vvc::vvcm_CommitArgs {
 95→                files: vec![
 96→                    gallops_path,
 97→                    src_paddock_path,
 98→                    dest_paddock_path,
 99→                ],
100→                message: format_heat_message(&dest_fm, HeatAction::Draft, &format!("{} → {}", coronet, result.new_coronet)),
101→                size_limit: 50000,
102→                warn_limit: 30000,
103→            };
104→
105→            match vvc::machine_commit(&lock, &commit_args) {
106→                Ok(hash) => {
107→                    eprintln!("jjx_draft: committed {}", &hash[..8]);
108→                }
109→                Err(e) => {
110→                    eprintln!("jjx_draft: commit warning: {}", e);
111→                }
112→            }
113→
114→            println!("{}", result.new_coronet);
115→            0
116→        }
117→        Err(e) => {
118→            eprintln!("jjx_draft: error: {}", e);
119→            1
120→        }
121→    }
122→    // lock released here
123→}
