  5→//! Wrap command - mark a pace complete with automated commit
  6→//!
  7→//! Stages all changes, generates a commit message with Claude,
  8→//! and transitions the pace state to complete with chalk marker.
  9→
 10→use std::path::PathBuf;
 11→use std::process::Command;
 12→use std::io::Write;
 13→
 14→use crate::jjrf_favor::{jjrf_Coronet as Coronet};
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_TallyArgs as LibTallyArgs, jjrg_PaceState};
 16→use crate::jjrn_notch::{jjrn_ChalkMarker, jjrn_format_notch_prefix, jjrn_format_chalk_message};
 17→
 18→/// Arguments for jjx_wrap command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrx_WrapArgs {
 21→    /// Pace identity (Coronet)
 22→    pub coronet: String,
 23→
 24→    /// Size limit in bytes (overrides default 50KB guard)
 25→    #[arg(long)]
 26→    pub size_limit: Option<u64>,
 27→}
 28→
 29→/// Helper to get pace silks or return default message
 30→fn get_pace_silks_or_default(gallops: &Gallops, firemark_key: &str, coronet_key: &str) -> String {
 31→    gallops.heats
 32→        .get(firemark_key)
 33→        .and_then(|heat| heat.paces.get(coronet_key))
 34→        .and_then(|pace| pace.tacks.first())
 35→        .map(|tack| format!("pace {} complete", tack.silks))
 36→        .unwrap_or_else(|| "pace complete".to_string())
 37→}
 38→
 39→/// Execute wrap command - mark pace complete with commit
 40→///
 41→/// Stages all changes, checks size, generates commit message using Claude,
 42→/// creates the work commit, then transitions pace to complete state with
 43→/// chalk marker commit.
 44→///
 45→/// Returns exit code (0 for success, non-zero for failure).
 46→pub fn zjjrx_run_wrap(args: jjrx_WrapArgs, summary: Option<String>) -> i32 {
 47→    // Parse coronet
 48→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
 49→        Ok(c) => c,
 50→        Err(e) => {
 51→            eprintln!("jjx_wrap: error: {}", e);
 52→            return 1;
 53→        }
 54→    };
 55→
 56→    let stdin_summary = summary;
 57→
 58→    // Acquire commit lock
 59→    let _lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 60→        Ok(l) => l,
 61→        Err(e) => {
 62→            eprintln!("jjx_wrap: error: {}", e);
 63→            return 1;
 64→        }
 65→    };
 66→
 67→    // Stage all changes
 68→    let add_output = match Command::new("git")
 69→        .args(["add", "-A"])
 70→        .output()
 71→    {
 72→        Ok(o) => o,
 73→        Err(e) => {
 74→            eprintln!("jjx_wrap: error: failed to run git add: {}", e);
 75→            return 1;
 76→        }
 77→    };
 78→
 79→    if !add_output.status.success() {
 80→        eprintln!("jjx_wrap: error: git add failed");
 81→        return 1;
 82→    }
 83→
 84→    // Size guard check
 85→    let size_limit = args.size_limit.unwrap_or(50000); // 50KB default
 86→    let diff_output = match Command::new("git")
 87→        .args(["diff", "--cached", "--stat"])
 88→        .output()
 89→    {
 90→        Ok(o) => o,
 91→        Err(e) => {
 92→            eprintln!("jjx_wrap: error: failed to run git diff: {}", e);
 93→            return 1;
 94→        }
 95→    };
 96→
 97→    if !diff_output.status.success() {
 98→        eprintln!("jjx_wrap: error: git diff failed");
 99→        return 1;
100→    }
101→
102→    // Parse size from last line of --stat output (format: "N files changed, M insertions(+), K deletions(-)")
103→    // Better size check: get actual staged content size
104→    let numstat_output = match Command::new("git")
105→        .args(["diff", "--cached", "--numstat"])
106→        .output()
107→    {
108→        Ok(o) => o,
109→        Err(e) => {
110→            eprintln!("jjx_wrap: error: failed to run git diff --numstat: {}", e);
111→            return 1;
112→        }
113→    };
114→
115→    if !numstat_output.status.success() {
116→        eprintln!("jjx_wrap: error: git diff --numstat failed");
117→        return 1;
118→    }
119→
120→    let numstat_str = String::from_utf8_lossy(&numstat_output.stdout);
121→    let mut total_size: u64 = 0;
122→    for line in numstat_str.lines() {
123→        let parts: Vec<&str> = line.split_whitespace().collect();
124→        if parts.len() >= 2 {
125→            // Format: added\tdeleted\tfilename
126→            if let Ok(added) = parts[0].parse::<u64>() {
127→                total_size += added;
128→            }
129→            if let Ok(deleted) = parts[1].parse::<u64>() {
130→                total_size += deleted;
131→            }
132→        }
133→    }
134→
135→    if total_size > size_limit {
136→        eprintln!("jjx_wrap: error: staged changes exceed size limit ({} > {} bytes)", total_size, size_limit);
137→        // Lock released automatically by Drop
138→        return 2;
139→    }
140→
141→    // Check if there are staged changes to commit
142→    let has_staged_changes = !numstat_str.trim().is_empty();
143→
144→    // Only generate commit message and commit if there are staged changes
145→    let commit_hash = if has_staged_changes {
146→        // Generate commit message using Claude CLI
147→        let diff_content = match Command::new("git")
148→            .args(["diff", "--cached"])
149→            .output()
150→        {
151→            Ok(o) => o,
152→            Err(e) => {
153→                eprintln!("jjx_wrap: error: failed to run git diff --cached: {}", e);
154→                return 1;
155→            }
156→        };
157→
158→        if !diff_content.status.success() {
159→            eprintln!("jjx_wrap: error: git diff --cached failed");
160→            return 1;
161→        }
162→
163→        let mut claude_cmd = match vvc::vvce_claude_command()
164→            .args([
165→                "--print",
166→                &format!("Generate a concise commit message for this diff. The commit wraps pace {}. Output only the message, no quotes.", args.coronet)
167→            ])
168→            .stdin(std::process::Stdio::piped())
169→            .stdout(std::process::Stdio::piped())
170→            .stderr(std::process::Stdio::piped())
171→            .spawn()
172→        {
173→            Ok(c) => c,
174→            Err(e) => {
175→                eprintln!("jjx_wrap: error: failed to spawn claude command: {}", e);
176→                return 1;
177→            }
178→        };
179→
180→        // Write diff to stdin
181→        if let Some(mut stdin) = claude_cmd.stdin.take() {
182→            if let Err(e) = stdin.write_all(&diff_content.stdout) {
183→                eprintln!("jjx_wrap: error: failed to write to claude stdin: {}", e);
184→                return 1;
185→            }
186→        }
187→
188→        let claude_output = match claude_cmd.wait_with_output() {
189→            Ok(o) => o,
190→            Err(e) => {
191→                eprintln!("jjx_wrap: error: failed to wait for claude: {}", e);
192→                return 1;
193→            }
194→        };
195→
196→        if !claude_output.status.success() {
197→            eprintln!("jjx_wrap: error: claude command failed");
198→            eprintln!("{}", String::from_utf8_lossy(&claude_output.stderr));
199→            return 1;
200→        }
201→
202→        let generated_message = String::from_utf8_lossy(&claude_output.stdout).trim().to_string();
203→
204→        // Commit with git directly (already staged via git add -A)
205→        let prefix = jjrn_format_notch_prefix(&coronet);
206→        let full_message = format!("{}{}\n\nCo-Authored-By: Claude <noreply@anthropic.com>", prefix, generated_message);
207→
208→        let commit_output = match Command::new("git")
209→            .args(["commit", "-m", &full_message])
210→            .output()
211→        {
212→            Ok(o) => o,
213→            Err(e) => {
214→                eprintln!("jjx_wrap: error: failed to run git commit: {}", e);
215→                return 1;
216→            }
217→        };
218→
219→        if !commit_output.status.success() {
220→            eprintln!("jjx_wrap: error: git commit failed");
221→            eprintln!("{}", String::from_utf8_lossy(&commit_output.stderr));
222→            return 1;
223→        }
224→
225→        // Get commit hash
226→        let hash_output = match Command::new("git")
227→            .args(["rev-parse", "HEAD"])
228→            .output()
229→        {
230→            Ok(o) => o,
231→            Err(e) => {
232→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
233→                return 1;
234→            }
235→        };
236→
237→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
238→    } else {
239→        // No staged changes - this is valid for verification-only paces
240→        eprintln!("jjx_wrap: no staged changes, proceeding with state transition only");
241→
242→        // Get current HEAD as reference (no new work commit created)
243→        let hash_output = match Command::new("git")
244→            .args(["rev-parse", "HEAD"])
245→            .output()
246→        {
247→            Ok(o) => o,
248→            Err(e) => {
249→                eprintln!("jjx_wrap: error: failed to get commit hash: {}", e);
250→                return 1;
251→            }
252→        };
253→
254→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
255→    };
256→
257→    // Transition pace state to complete
258→    let gallops_path = PathBuf::from(".claude/jjm/jjg_gallops.json");
259→    let mut gallops = match Gallops::jjrg_load(&gallops_path) {
260→        Ok(g) => g,
261→        Err(e) => {
262→            eprintln!("jjx_wrap: error loading Gallops: {}", e);
263→            return 1;
264→        }
265→    };
266→
267→    let tally_args = LibTallyArgs {
268→        coronet: args.coronet.clone(),
269→        state: Some(jjrg_PaceState::Complete),
270→        direction: None,
271→        text: None,
272→        silks: None,
273→    };
274→
275→    if let Err(e) = gallops.jjrg_tally(tally_args) {
276→        eprintln!("jjx_wrap: error: {}", e);
277→        return 1;
278→    }
279→
280→    // Save gallops
281→    if let Err(e) = gallops.jjrg_save(&gallops_path) {
282→        eprintln!("jjx_wrap: error saving Gallops: {}", e);
283→        return 1;
284→    }
285→
286→    // Build chalk description: use stdin if provided, else "pace {silks} complete"
287→    let firemark = coronet.jjrf_parent_firemark();
288→    let firemark_key = firemark.jjrf_display();
289→    let coronet_key = coronet.jjrf_display();
290→
291→    let chalk_description = if let Some(ref text) = stdin_summary {
292→        let trimmed = text.trim();
293→        if !trimmed.is_empty() {
294→            trimmed.to_string()
295→        } else {
296→            // Empty stdin - use default with silks
297→            get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
298→        }
299→    } else {
300→        // No stdin - use default with silks
301→        get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
302→    };
303→
304→    // Create W chalk marker commit with gallops state change
305→    let chalk_message = jjrn_format_chalk_message(&coronet, jjrn_ChalkMarker::Wrap, &chalk_description);
306→
307→    let chalk_commit_args = vvc::vvcm_CommitArgs {
308→        files: vec![".claude/jjm/jjg_gallops.json".to_string()],
309→        message: chalk_message,
310→        size_limit: vvc::VVCG_SIZE_LIMIT,
311→        warn_limit: vvc::VVCG_WARN_LIMIT,
312→    };
313→
314→    match vvc::machine_commit(&_lock, &chalk_commit_args) {
315→        Ok(_) => {
316→            println!("{}", commit_hash);
317→            let fm = coronet.jjrf_parent_firemark();
318→            let fm_key = fm.jjrf_display();
319→            let fm_str = fm.jjrf_as_str();
320→
321→            // Lookahead: find next actionable pace in this heat
322→            let next_pace_info = gallops.heats.get(&fm_key).and_then(|heat| {
323→                heat.order.iter().find_map(|c| {
324→                    heat.paces.get(c.as_str()).and_then(|pace| {
325→                        pace.tacks.first().and_then(|tack| {
326→                            match tack.state {
327→                                jjrg_PaceState::Rough | jjrg_PaceState::Bridled => {
328→                                    Some((c.clone(), tack.silks.clone()))
329→                                }
330→                                _ => None,
331→                            }
332→                        })
333→                    })
334→                })
335→            });
336→
337→            eprintln!();
338→            match next_pace_info {
339→                Some((next_coronet, next_silks)) => {
340→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. Next: {} (\u{20a2}{}) \u{2014} `/clear` then `/jjc-heat-mount {}`",
341→                        args.coronet, next_silks, next_coronet, fm_str);
342→                }
343→                None => {
344→                    eprintln!("AGENT_RESPONSE: \u{20a2}{} wrapped. All paces complete \u{2014} `/clear` then `/jjc-heat-retire {}`",
345→                        args.coronet, fm_str);
346→                }
347→            }
348→            0
349→        }
350→        Err(e) => {
351→            eprintln!("jjx_wrap: error: chalk commit failed: {}", e);
352→            eprintln!("jjx_wrap: warning: gallops state updated but not committed");
353→            1
354→        }
355→    }
356→    // lock released here
357→}
