  5→//! Scout command - Search across heats and paces with regex
  6→
  7→use clap::Args;
  8→use std::path::PathBuf;
  9→use regex::Regex;
 10→use std::fs;
 11→
 12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
 13→
 14→/// Arguments for jjx_scout command
 15→#[derive(Args, Debug)]
 16→pub struct jjrsc_ScoutArgs {
 17→    /// Path to the Gallops JSON file
 18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 19→    pub file: PathBuf,
 20→
 21→    /// Regex pattern to search for
 22→    pub pattern: String,
 23→
 24→    /// Limit to actionable paces only (rough/bridled)
 25→    #[arg(long)]
 26→    pub actionable: bool,
 27→}
 28→
 29→/// Run the scout command - regex search across heats/paces
 30→pub fn jjrsc_run_scout(args: jjrsc_ScoutArgs) -> i32 {
 31→    use regex::RegexBuilder;
 32→
 33→    let gallops = match Gallops::jjrg_load(&args.file) {
 34→        Ok(g) => g,
 35→        Err(e) => {
 36→            eprintln!("jjx_scout: error: {}", e);
 37→            return 1;
 38→        }
 39→    };
 40→
 41→    // Build case-insensitive regex
 42→    let re = match RegexBuilder::new(&args.pattern)
 43→        .case_insensitive(true)
 44→        .build()
 45→    {
 46→        Ok(r) => r,
 47→        Err(e) => {
 48→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
 49→            return 1;
 50→        }
 51→    };
 52→
 53→    // Track which heats have matches (for group headers)
 54→    let mut current_heat_key: Option<String> = None;
 55→
 56→    // Iterate all heats (racing, stabled, retired)
 57→    for (heat_key, heat) in &gallops.heats {
 58→        // Search each pace in order
 59→        for coronet_key in &heat.order {
 60→            if let Some(pace) = heat.paces.get(coronet_key) {
 61→                if let Some(tack) = pace.tacks.first() {
 62→                    // Apply actionable filter if requested
 63→                    if args.actionable {
 64→                        match tack.state {
 65→                            PaceState::Rough | PaceState::Bridled => {},
 66→                            _ => continue,
 67→                        }
 68→                    }
 69→
 70→                    // Search: silks, spec (tack text), direction, paddock content
 71→                    // Use owned strings to avoid lifetime issues
 72→                    let mut match_result: Option<(String, String)> = None;
 73→
 74→                    if re.is_match(&tack.silks) {
 75→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
 76→                    } else if re.is_match(&tack.text) {
 77→                        match_result = Some(("spec".to_string(), tack.text.clone()));
 78→                    } else if let Some(ref direction) = tack.direction {
 79→                        if re.is_match(direction) {
 80→                            match_result = Some(("direction".to_string(), direction.clone()));
 81→                        }
 82→                    } else {
 83→                        // Search paddock content
 84→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
 85→                        if let Ok(content) = fs::read_to_string(paddock_path) {
 86→                            if re.is_match(&content) {
 87→                                match_result = Some(("paddock".to_string(), content));
 88→                            }
 89→                        }
 90→                    }
 91→
 92→                    // If we found a match, output it
 93→                    if let Some((field_name, field_content)) = match_result {
 94→                        // Print heat header if this is a new heat
 95→                        if current_heat_key.as_ref() != Some(heat_key) {
 96→                            println!("{} {}", heat_key, heat.silks);
 97→                            current_heat_key = Some(heat_key.clone());
 98→                        }
 99→
100→                        // Print pace line
101→                        let state_str = zjrsc_pace_state_str(&tack.state);
102→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
103→
104→                        // Print match line with context (extract ~60 chars around match)
105→                        let match_excerpt = zjrsc_extract_match_context(&field_content, &re);
106→                        println!("    {}: {}", field_name, match_excerpt);
107→                    }
108→                }
109→            }
110→        }
111→    }
112→
113→    0
114→}
115→
116→/// Helper to convert PaceState to display string
117→pub(crate) fn zjrsc_pace_state_str(state: &PaceState) -> &'static str {
118→    match state {
119→        PaceState::Rough => "rough",
120→        PaceState::Bridled => "bridled",
121→        PaceState::Complete => "complete",
122→        PaceState::Abandoned => "abandoned",
123→    }
124→}
125→
126→/// Extract context around the first regex match in content
127→pub(crate) fn zjrsc_extract_match_context(content: &str, re: &Regex) -> String {
128→    if let Some(mat) = re.find(content) {
129→        let start = mat.start();
130→        let end = mat.end();
131→
132→        // Find context window (30 chars before, 30 chars after)
133→        let context_before = 30;
134→        let context_after = 30;
135→
136→        // Snap window boundaries to valid UTF-8 char boundaries
137→        let mut window_start = start.saturating_sub(context_before);
138→        while !content.is_char_boundary(window_start) {
139→            window_start -= 1;
140→        }
141→
142→        let mut window_end = (end + context_after).min(content.len());
143→        while !content.is_char_boundary(window_end) {
144→            window_end += 1;
145→        }
146→        let window_end = window_end.min(content.len());
147→
148→        let mut excerpt = String::new();
149→        if window_start > 0 {
150→            excerpt.push_str("...");
151→        }
152→        excerpt.push_str(&content[window_start..window_end]);
153→        if window_end < content.len() {
154→            excerpt.push_str("...");
155→        }
156→
157→        // Replace newlines with spaces for single-line display
158→        excerpt.replace('\n', " ").replace('\r', "")
159→    } else {
160→        // Shouldn't happen, but fallback to truncated content
161→        let truncated = content.chars().take(60).collect::<String>();
162→        if content.len() > 60 {
163→            format!("{}...", truncated)
164→        } else {
165→            truncated
166→        }
167→    }
168→}
