 5→//! Get spec command - Extract spec text for a pace
 6→//!
 7→//! Implements the `jjx_get_spec` command which retrieves and outputs the raw
 8→//! specification text for a single pace.
 9→
10→use std::path::PathBuf;
11→use clap::Args;
12→
13→use crate::jjrf_favor::jjrf_Coronet as Coronet;
14→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
15→
16→/// Arguments for jjx_get_spec command
17→#[derive(Args, Debug)]
18→pub struct jjrgs_GetSpecArgs {
19→    /// Path to the Gallops JSON file
20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
21→    pub file: PathBuf,
