  5→//! Garland command - celebrate heat completion and create continuation
  6→//!
  7→//! Garlanding a heat:
  8→//! - Updates source heat silks to garlanded form and status to stabled
  9→//! - Creates new heat with continuation silks, status racing
 10→//! - Transfers actionable paces (rough/bridled) to new heat
 11→//! - Retains complete/abandoned paces in garlanded heat
 12→
 13→use std::path::PathBuf;
 14→
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_GarlandArgs as LibGarlandArgs};
 16→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
 17→use crate::jjri_io::jjri_paddock_path;
 18→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 19→
 20→/// Arguments for jjx_garland command
 21→#[derive(clap::Args, Debug)]
 22→pub struct jjrgl_GarlandArgs {
 23→    /// Path to the Gallops JSON file
 24→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 25→    pub file: PathBuf,
 26→
 27→    /// Heat to garland (Firemark)
 28→    pub firemark: String,
 29→}
 30→
 31→/// Run the garland command
 32→///
 33→/// Executes garland operation, saves gallops, and commits the result.
 34→/// Returns exit code (0 for success, non-zero for failure).
 35→pub fn jjrgl_run_garland(args: jjrgl_GarlandArgs) -> i32 {
 36→    use std::path::Path;
 37→
 38→    // Acquire lock FIRST - fail fast if another operation is in progress
 39→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 40→        Ok(l) => l,
 41→        Err(e) => {
 42→            eprintln!("jjx_garland: error: {}", e);
 43→            return 1;
 44→        }
 45→    };
 46→
 47→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 48→        Ok(g) => g,
 49→        Err(e) => {
 50→            eprintln!("jjx_garland: error loading Gallops: {}", e);
 51→            return 1;
 52→        }
 53→    };
 54→
 55→    let firemark_str = args.firemark.clone();
 56→
 57→    // Compute base path from gallops file
 58→    let base_path = args.file.parent()
 59→        .and_then(|p| p.parent())
 60→        .and_then(|p| p.parent())
 61→        .unwrap_or(Path::new("."));
 62→
 63→    let garland_args = LibGarlandArgs {
 64→        firemark: firemark_str.clone(),
 65→    };
 66→
 67→    // Execute garland operation
 68→    let result = match gallops.jjrg_garland(garland_args, base_path) {
 69→        Ok(r) => r,
 70→        Err(e) => {
 71→            eprintln!("jjx_garland: error: {}", e);
 72→            return 1;
 73→        }
 74→    };
 75→
 76→    // Save gallops
 77→    if let Err(e) = gallops.jjrg_save(&args.file) {
 78→        eprintln!("jjx_garland: error saving Gallops: {}", e);
 79→        return 1;
 80→    }
 81→
 82→    // Parse both firemarks for commit file list
 83→    let old_fm = Firemark::jjrf_parse(&result.old_firemark).expect("garland returned invalid old firemark");
 84→    let new_fm = Firemark::jjrf_parse(&result.new_firemark).expect("garland returned invalid new firemark");
 85→
 86→    let gallops_path = args.file.to_string_lossy().to_string();
 87→    let old_paddock_path = jjri_paddock_path(old_fm.jjrf_as_str());
 88→    let new_paddock_path = jjri_paddock_path(new_fm.jjrf_as_str());
 89→
 90→    // Build commit message using heat-level Garland action
 91→    let commit_message = format_heat_message(
 92→        &old_fm,
 93→        HeatAction::Garland,
 94→        &format!("{} → {}", result.old_silks, result.new_silks)
 95→    );
 96→
 97→    let commit_args = vvc::vvcm_CommitArgs {
 98→        files: vec![
 99→            gallops_path,
100→            old_paddock_path,
101→            new_paddock_path,
102→        ],
103→        message: commit_message,
104→        size_limit: 100000,  // 100KB - paddock files can be large
105→        warn_limit: 50000,
106→    };
107→
108→    match vvc::machine_commit(&lock, &commit_args) {
109→        Ok(hash) => {
110→            eprintln!("jjx_garland: committed {}", &hash[..8]);
111→        }
112→        Err(e) => {
113→            eprintln!("jjx_garland: commit warning: {}", e);
114→        }
115→    }
116→
117→    // Output JSON result
118→    let output = serde_json::json!({
119→        "old_firemark": result.old_firemark,
120→        "old_silks": result.old_silks,
121→        "new_firemark": result.new_firemark,
122→        "new_silks": result.new_silks,
123→        "paces_transferred": result.paces_transferred,
124→        "paces_retained": result.paces_retained,
125→    });
126→
127→    match serde_json::to_string_pretty(&output) {
128→        Ok(json) => {
129→            println!("{}", json);
130→            0
131→        }
132→        Err(e) => {
133→            eprintln!("jjx_garland: error serializing output: {}", e);
134→            1
135→        }
136→    }
137→    // lock released here
138→}
