  5→//! Restring command - bulk draft multiple paces between heats
  6→//!
  7→//! Handles the jjx_restring command which moves multiple paces from one heat
  8→//! to another in a single atomic operation.
  9→
 10→use std::path::PathBuf;
 11→
 12→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RestringArgs as LibRestringArgs, jjrg_PaceState};
 14→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 15→
 16→/// Arguments for jjx_restring command
 17→#[derive(clap::Args, Debug)]
 18→pub struct jjrrs_RestringArgs {
 19→    /// Path to the Gallops JSON file
 20→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 21→    pub file: PathBuf,
 22→
 23→    /// Source Heat identity (Firemark)
 24→    pub firemark: String,
 25→
 26→    /// Destination Heat identity (Firemark)
 27→    #[arg(long)]
 28→    pub to: String,
 29→}
 30→
 31→/// Execute restring command - bulk draft multiple paces atomically
 32→pub fn jjrrs_run(args: jjrrs_RestringArgs, coronets: String) -> i32 {
 33→    // Acquire lock FIRST - fail fast if another operation is in progress
 34→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 35→        Ok(l) => l,
 36→        Err(e) => {
 37→            eprintln!("jjx_restring: error: {}", e);
 38→            return 1;
 39→        }
 40→    };
 41→
 42→    let coronets: Vec<String> = match serde_json::from_str(&coronets) {
 43→        Ok(c) => c,
 44→        Err(e) => {
 45→            eprintln!("jjx_restring: error: Expected JSON array of coronets: {}", e);
 46→            return 1;
 47→        }
 48→    };
 49→
 50→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 51→        Ok(g) => g,
 52→        Err(e) => {
 53→            eprintln!("jjx_restring: error loading Gallops: {}", e);
 54→            return 1;
 55→        }
 56→    };
 57→
 58→    let restring_args = LibRestringArgs {
 59→        source_firemark: args.firemark.clone(),
 60→        dest_firemark: args.to.clone(),
 61→        coronets,
 62→    };
 63→
 64→    // Execute restring operation
 65→    let result = match gallops.jjrg_restring(restring_args) {
 66→        Ok(r) => r,
 67→        Err(e) => {
 68→            eprintln!("jjx_restring: error: {}", e);
 69→            return 1;
 70→        }
 71→    };
 72→
 73→    // Save gallops
 74→    if let Err(e) = gallops.jjrg_save(&args.file) {
 75→        eprintln!("jjx_restring: error saving Gallops: {}", e);
 76→        return 1;
 77→    }
 78→
 79→    // Parse both firemarks for commit file list
 80→    let dest_fm = Firemark::jjrf_parse(&result.dest_firemark).expect("restring returned invalid dest firemark");
 81→
 82→    let gallops_path = args.file.to_string_lossy().to_string();
 83→    let source_paddock_path = result.source_paddock.clone();
 84→    let dest_paddock_path = result.dest_paddock.clone();
 85→
 86→    // Build commit message using heat-level action
 87→    let commit_message = format_heat_message(
 88→        &dest_fm,
 89→        HeatAction::Draft,  // Reusing Draft action since this is a bulk draft operation
 90→        &format!("restring {} paces from {}", result.drafted.len(), result.source_firemark)
 91→    );
 92→
 93→    let commit_args = vvc::vvcm_CommitArgs {
 94→        files: vec![
 95→            gallops_path,
 96→            source_paddock_path,
 97→            dest_paddock_path,
 98→        ],
 99→        message: commit_message,
100→        size_limit: 100000,  // 100KB - bulk operations can be large
101→        warn_limit: 50000,
102→    };
103→
104→    match vvc::machine_commit(&lock, &commit_args) {
105→        Ok(hash) => {
106→            eprintln!("jjx_restring: committed {}", &hash[..8]);
107→        }
108→        Err(e) => {
109→            eprintln!("jjx_restring: commit warning: {}", e);
110→        }
111→    }
112→
113→    // Output JSON result
114→    let drafted_json: Vec<_> = result.drafted.iter().map(|m| {
115→        serde_json::json!({
116→            "old_coronet": m.old_coronet,
117→            "new_coronet": m.new_coronet,
118→            "silks": m.silks,
119→            "state": match m.state {
120→                jjrg_PaceState::Rough => "rough",
121→                jjrg_PaceState::Bridled => "bridled",
122→                jjrg_PaceState::Complete => "complete",
123→                jjrg_PaceState::Abandoned => "abandoned",
124→            },
125→            "spec": m.spec,
126→        })
127→    }).collect();
128→
129→    let output = serde_json::json!({
130→        "source": {
131→            "firemark": result.source_firemark,
132→            "silks": result.source_silks,
133→            "paddock": result.source_paddock,
134→            "empty_after": result.source_empty_after,
135→        },
136→        "destination": {
137→            "firemark": result.dest_firemark,
138→            "silks": result.dest_silks,
139→            "paddock": result.dest_paddock,
140→        },
141→        "drafted": drafted_json,
142→    });
143→
144→    match serde_json::to_string_pretty(&output) {
145→        Ok(json) => {
146→            println!("{}", json);
147→            0
148→        }
149→        Err(e) => {
150→            eprintln!("jjx_restring: error serializing output: {}", e);
151→            1
152→        }
153→    }
154→    // lock released here
155→}
